27	export function timeUntil(iso: string): string {
28	  const diff = new Date(iso).getTime() - Date.now();
29	  if (diff <= 0) return "expired";
30	  const hours = Math.floor(diff / 3_600_000);
31	  const days = Math.floor(hours / 24);
32	  if (days > 0) return `${days}d ${hours % 24}h`;
33	  const mins = Math.floor((diff % 3_600_000) / 60_000);
34	  return `${hours}h ${mins}m`;
35	}
